            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[PairOrderRequestMessage](sbeTemplateId=");
            builder.Append(PairOrderRequestMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(PairOrderRequestMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != PairOrderRequestMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(PairOrderRequestMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != PairOrderRequestMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(PairOrderRequestMessage.BlockLength);
            builder.Append("):");

            builder.Append("PairOrderRequestType=");
            builder.Append(this.PairOrderRequestType);
            builder.Append('|');
            builder.Append("OrderType=");
            builder.Append(this.OrderType);
            builder.Append('|');
            builder.Append("TriggerValue=");
            builder.Append(this.TriggerValue);
            builder.Append('|');
            builder.Append("BuyTermsRatio=");
